248	static jinja::value_string format_using_direct_engine(
249	            const std::string & template_str,
250	            json & input) {
251	    // lexing
252	    jinja::lexer lexer;
253	    auto lexer_res = lexer.tokenize(template_str);
254	
255	    // compile to AST
256	    jinja::program ast = jinja::parse_from_tokens(lexer_res);
257	
258	    // check caps for workarounds
259	    jinja::caps_get(ast);
260	
261	    std::cout << "\n=== RUN ===\n";
262	    jinja::context ctx(template_str);
263	
264	    jinja::global_from_json(ctx, input, true);
265	
266	    jinja::runtime runtime(ctx);
267	    const jinja::value results = runtime.execute(ast);
268	    auto parts = jinja::runtime::gather_string_parts(results);
269	
270	    std::cout << "\n=== RESULTS ===\n";
271	    for (const auto & part : parts->as_string().parts) {
272	        std::cout << (part.is_input ? "DATA" : "TMPL") << ": " << part.val << "\n";
273	    }
274	
275	    return parts;
276	}
